const fs = require('fs');
const path = require('path');
const { execSync } = require('child_process');

async function runTest() {
  // Create a 100x100 red jpeg image buffer using raw pixel data (a simple BMP or using sharp if available)
  // We'll just generate a valid JPG using a built-in command or write a base64 string
  
  const testImgPath = path.join(__dirname, 'test2.jpg');
  
  // Using the test2.jpg generated by sharp

  console.log('Test image created.');

  // Start the server in the background for a moment
  console.log('Starting server...');
  try {
    const FormData = require('form-data');
    const fetch = require('node-fetch');

    const form = new FormData();
    form.append('image', fs.createReadStream(testImgPath));

    console.log('Uploading test image to http://localhost:4000/upload');
    const response = await fetch('http://localhost:4000/upload', {
      method: 'POST',
      body: form
    });

    const data = await response.json();
    console.log('Response:', data);

    if (data.success && data.thumbnailUrl.endsWith('.webp')) {
      console.log('SUCCESS: WebP URLs were returned.');
      
      const rootAssetDir = path.join(__dirname, '../../.data/assets/processed');
      const files = fs.readdirSync(rootAssetDir);
      const webpFiles = files.filter(f => f.endsWith('.webp'));
      console.log(`Found ${webpFiles.length} WebP files in .data/assets/processed:`, webpFiles);
      
      if (webpFiles.length >= 3) {
        console.log('VERIFICATION COMPLETE: WebP conversion is working!');
      } else {
        console.error('VERIFICATION FAILED: Did not find 3 generated WebP files.');
      }

    } else {
      console.error('FAILED: Invalid response.', data);
    }
  } catch (err) {
    console.error('Error during test:', err);
  }
}

runTest();
